@import "@ralph/ui/styles.css";
@tailwind components;
@tailwind utilities;
:root {
  --cream: #fbfaf6;
  --surface: #ffffff;
  --soft: #f4f0e7;
  --ink: #111111;
  --muted: #625c52;
  --blue: #2f62e9;
  --blue-dark: #204cc0;
  --gold: #ffd84d;
  --clay: #ff7448;
  --line: #e6ded0;
  --shadow: 0 22px 60px rgba(60, 45, 26, 0.12);
  --radius: 28px;
  --font-xs:        0.7rem;
  --font-label:     clamp(0.75rem, 0.9vw, 0.875rem);
  --font-body:      clamp(0.875rem, 1.1vw, 1rem);
  --font-card:      clamp(1rem, 1.4vw, 1.15rem);
  --font-section:   clamp(1.1rem, 1.6vw, 1.35rem);
  --font-page:      clamp(1.4rem, 2.2vw, 1.9rem);
  --font-heading:   clamp(1.25rem, 2.2vw, 1.875rem);
  --font-display:   clamp(1.6rem, 3vw, 2.4rem);
  --font-hero:      clamp(2rem, 4.2vw, 3.25rem);
  --font-stat:      clamp(1.2rem, 1.8vw, 1.5rem);
  --font-stat-label: 0.72rem;
  --nav-offset: 96px;
}
* {
  box-sizing: border-box;
}
button,
input,
textarea {
  border-style: solid;
}
html {
  scroll-behavior: smooth;
}
body {
  margin: 0;
  background: var(--cream);
  color: var(--ink);
  font-family: "Trebuchet MS", "Avenir Next", Avenir, Arial, sans-serif;
  font-size: var(--font-body);
  text-rendering: geometricPrecision;
}
a {
  color: inherit;
  text-decoration: none;
}
button,
input {
  font: inherit;
}
main {
  overflow-x: clip;
  overflow-y: visible;
}
h1,
h2,
h3,
p {
  margin-top: 0;
}
h1 {
  max-width: 920px;
  margin: 34px 0 18px;
  font-size: var(--font-hero);
  font-weight: 520;
  letter-spacing: -0.062em;
  line-height: 1;
}
h2 {
  margin-bottom: 16px;
  font-size: var(--font-heading);
  font-weight: 520;
  letter-spacing: -0.042em;
  line-height: 1.08;
}
h3 {
  margin: 0 0 14px;
  font-size: var(--font-heading);
  letter-spacing: -0.04em;
  line-height: 1.06;
}
.button,
.check-panel button {
  display: inline-flex;
  min-height: 56px;
  align-items: center;
  justify-content: center;
  border: 0;
  border-radius: 21px;
  background: var(--blue);
  color: var(--surface);
  cursor: pointer;
  font-weight: 900;
  padding: 0 30px;
  box-shadow: 0 14px 28px rgba(47, 98, 233, 0.2);
  transition: transform 180ms ease, background 180ms ease, box-shadow 180ms ease;
}
.button:hover,
.button:focus-visible,
.check-panel button:hover,
.check-panel button:focus-visible {
  background: var(--blue-dark);
  box-shadow: 0 18px 34px rgba(47, 98, 233, 0.27);
  transform: translateY(-2px);
}
.button:focus-visible,
.check-panel button:focus-visible,
input:focus-visible,
a:focus-visible {
  outline: 3px solid rgba(47, 98, 233, 0.32);
  outline-offset: 4px;
}
.setup-missing {
  min-height: 100vh;
  display: grid;
  place-items: center;
  padding: 20px;
}
.setup-missing h1 {
  margin: 0 0 12px;
  font-size: clamp(1.4rem, 2.4vw, 1.9rem);
  font-weight: 900;
  letter-spacing: -0.04em;
  line-height: 1.1;
}
.setup-missing p {
  margin: 0 0 12px;
  color: var(--muted);
  font-size: var(--font-label);
  font-weight: 700;
  line-height: 1.35;
}
.setup-missing ul {
  margin: 0 0 16px;
  padding-left: 18px;
  display: grid;
  gap: 6px;
  color: var(--ink);
  font-size: var(--font-label);
  font-weight: 700;
}
.setup-missing code {
  padding: 2px 6px;
  border-radius: 6px;
  background: var(--soft);
  color: var(--ink);
  font-size: 0.85em;
  font-weight: 850;
}
.global-layout-wrapper {
  display: flex;
  flex-direction: column;
  min-height: 100vh;
}
.global-main-content {
  flex: 1;
  display: flex;
  flex-direction: column;
}
@keyframes fadeIn {
  from { opacity: 0; transform: translateY(-10px); }
  to { opacity: 1; transform: translateY(0); }
}

@keyframes spin {
  to {
    transform: rotate(360deg);
  }
}
@media (max-width: 980px) {
  :root {
    --nav-offset: 0px;
  }
}

.check-section,
.answers-section,
.budget-section,
.pricing-section {
  padding: clamp(44px, 6vw, 72px) clamp(40px, 18vw, 260px);
}
.hero {
  position: relative;
  display: grid;
  justify-items: center;
  padding: clamp(30px, 5vw, 62px) clamp(40px, 18vw, 260px) clamp(20px, 3vw, 36px);
  text-align: center;
}
.pill {
  display: inline-flex;
  border-radius: 13px;
  background: var(--surface);
  box-shadow: 0 12px 30px rgba(47, 40, 30, 0.12);
  color: var(--blue);
  padding: 12px 20px;
}
.eyebrow {
  display: inline-flex;
  width: fit-content;
  margin: 0;
  color: var(--blue);
  font-size: var(--font-body);
  font-weight: 900;
  line-height: 1.25;
}
.hero-copy {
  max-width: 880px;
  margin-bottom: 22px;
  font-size: var(--font-body);
  font-weight: 700;
  letter-spacing: -0.032em;
  line-height: 1.32;
}
.hero-actions {
  display: grid;
  gap: 12px;
  justify-content: center;
}
.hero-actions p {
  max-width: 460px;
  margin: 0;
  color: var(--muted);
  font-size: var(--font-label);
  font-weight: 750;
  line-height: 1.3;
  text-align: center;
}
.dot {
  position: absolute;
  border-radius: 50%;
}
.dot-blue {
  top: 46%;
  left: 6%;
  width: 56px;
  height: 56px;
  background: var(--blue);
}
.dot-gold {
  top: 22%;
  right: 18%;
  width: 64px;
  height: 64px;
  background: var(--gold);
}
@media (max-width: 640px) {
  .hero {
    padding-top: 18px;
  }
  .dot {
    display: none;
  }
}
.check-section {
  display: grid;
  grid-template-columns: 1fr;
  gap: 40px;
  background: #eef3ff;
  padding-top: clamp(44px, 6vw, 74px);
}
.ai-explainer {
  max-width: 800px;
  margin: 0 auto;
  text-align: center;
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 24px;
  padding: 60px 20px 20px;
}
.ai-explainer h3 {
  font-size: clamp(28px, 5vw, 36px);
  color: #111;
  margin: 0;
  line-height: 1.2;
  letter-spacing: -0.02em;
}
.ai-explainer p {
  font-size: clamp(16px, 2.5vw, 18px);
  color: #555;
  max-width: 650px;
  line-height: 1.6;
  margin: 0;
}
.ai-explainer > div {
  display: flex;
  flex-wrap: wrap;
  gap: 12px;
  justify-content: center;
  margin-top: 16px;
}
.ai-explainer > div span {
  background: #fff;
  color: #2f62e9;
  padding: 10px 18px;
  border-radius: 999px;
  font-size: 15px;
  font-weight: 500;
  border: 1px solid rgba(47, 98, 233, 0.2);
  box-shadow: 0 4px 12px rgba(47, 98, 233, 0.05);
  transition: all 0.3s ease;
  cursor: default;
}
.ai-explainer > div span:hover {
  transform: translateY(-2px);
  box-shadow: 0 6px 16px rgba(47, 98, 233, 0.1);
  border-color: rgba(47, 98, 233, 0.3);
}
.answers-section {
  background: var(--cream);
}
.section-heading {
  max-width: 900px;
  margin-bottom: 38px;
}
.answer-grid {
  display: grid;
  grid-template-columns: repeat(3, 1fr);
  gap: 18px;
}
.answer-card {
  border-radius: var(--radius);
  background: var(--surface);
  box-shadow: var(--shadow);
  padding: 20px 22px;
  font-size: var(--font-body);
  font-weight: 850;
  letter-spacing: -0.026em;
  line-height: 1.18;
}
.budget-section {
  display: grid;
  grid-template-columns: 1fr minmax(340px, 0.8fr);
  gap: clamp(24px, 5vw, 60px);
  align-items: center;
  background: #fff6db;
}
.budget-text p:not(.eyebrow) {
  margin: 10px 0 0;
  color: var(--muted);
  font-size: var(--font-body);
  font-weight: 650;
  line-height: 1.35;
  max-width: 480px;
}
.cost-list {
  border-radius: var(--radius);
  background: var(--surface);
  box-shadow: var(--shadow);
  padding: 28px;
}
.cost-row,
.cost-total {
  display: flex;
  justify-content: space-between;
  gap: 18px;
  border-bottom: 1px solid var(--line);
  padding: 16px 0;
}
.cost-row:first-child {
  padding-top: 0;
}
.cost-row strong {
  font-size: var(--font-label);
}
.cost-total {
  align-items: end;
  border-bottom: 0;
  padding-bottom: 0;
}
.cost-total strong {
  color: var(--blue);
  font-size: var(--font-card);
  letter-spacing: -0.04em;
  line-height: 1;
}
.why-section {
  background: var(--surface);
  padding: clamp(48px, 6vw, 80px) clamp(40px, 18vw, 260px);
}
.why-grid {
  display: grid;
  grid-template-columns: repeat(3, minmax(0, 1fr));
  gap: 18px;
}
.why-card {
  display: grid;
  align-content: start;
  gap: 12px;
  min-height: 184px;
  border: 1px solid var(--line);
  border-radius: var(--radius);
  background: var(--cream);
  box-shadow: var(--shadow);
  padding: clamp(22px, 3vw, 30px);
  transition: transform 220ms ease, box-shadow 220ms ease;
}
.why-card:hover {
  transform: translateY(-2px);
  box-shadow: 0 28px 64px rgba(60, 45, 26, 0.16);
}
.why-icon {
  display: grid;
  width: 48px;
  height: 48px;
  place-items: center;
  border-radius: 14px;
  background: var(--ink);
  color: var(--surface);
}
.why-icon svg {
  width: 24px;
  height: 24px;
}
.why-card h3 {
  margin: 0;
  font-size: clamp(1.05rem, 1.6vw, 1.25rem);
  font-weight: 900;
  letter-spacing: -0.03em;
  line-height: 1.1;
}
.why-card p {
  margin: 0;
  color: var(--muted);
  font-size: var(--font-label);
  font-weight: 700;
  line-height: 1.36;
}
@media (max-width: 980px) {
  .why-grid {
    grid-template-columns: repeat(2, minmax(0, 1fr));
  }
}
@media (max-width: 640px) {
  .why-grid {
    grid-template-columns: 1fr;
  }
}
.pricing-section {
  padding: clamp(48px, 6vw, 80px) clamp(40px, 18vw, 260px);
  background: var(--surface);
}
.pricing-note {
  max-width: 760px;
  color: var(--muted);
  font-size: var(--font-body);
  font-weight: 700;
  line-height: 1.34;
}
.pricing-unlocks {
  margin: 0 auto 38px;
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 12px;
}
.pricing-unlocks span {
  font-size: var(--font-label);
  font-weight: 900;
  color: var(--blue);
  text-transform: uppercase;
  letter-spacing: 0.05em;
}
.pricing-unlocks ul {
  display: flex;
  flex-wrap: wrap;
  justify-content: center;
  gap: clamp(8px, 1.5vw, 16px);
  padding: 0;
  margin: 0;
  list-style: none;
}
.pricing-unlocks li {
  display: flex;
  align-items: center;
  gap: 6px;
  font-size: var(--font-label);
  font-weight: 800;
  color: var(--ink);
  background: var(--surface);
  border: 1px solid var(--line);
  padding: 6px 12px;
  border-radius: 999px;
  box-shadow: 0 2px 6px rgba(60, 45, 26, 0.04);
}
.pricing-unlocks li::before {
  content: "✓";
  color: var(--blue);
  font-weight: 900;
}
.pricing-grid {
  display: grid;
  grid-template-columns: repeat(3, 1fr);
  gap: 20px;
}
.price-card {
  border-radius: var(--radius);
  background: var(--surface);
  box-shadow: var(--shadow);
  display: grid;
  align-content: start;
  padding: clamp(20px, 2.5vw, 28px);
}
.price-card.featured {
  background: var(--blue);
  color: var(--surface);
}
.price-card.featured p {
  color: rgba(255, 255, 255, 0.78);
}
.price-card strong {
  display: block;
  margin: 4px 0 18px;
  font-size: var(--font-card);
  letter-spacing: -0.04em;
  line-height: 1;
}
.price-features {
  display: grid;
  gap: 10px;
  min-height: 132px;
  margin: 0 0 22px;
  padding: 0;
  list-style: none;
}
.price-features li {
  position: relative;
  color: var(--muted);
  font-size: var(--font-label);
  font-weight: 800;
  line-height: 1.3;
  padding-left: 18px;
}
.price-features li::before {
  position: absolute;
  left: 0;
  color: var(--blue);
  content: "•";
  font-weight: 900;
}
.price-card.featured .price-features li {
  color: rgba(255, 255, 255, 0.84);
}
.price-card.featured .price-features li::before {
  color: var(--gold);
}
.faqs-section {
  background: var(--cream);
  padding: clamp(48px, 6vw, 80px) clamp(40px, 18vw, 260px);
}
.faqs-list {
  display: grid;
  gap: 10px;
  margin: 0;
  padding: 0;
  list-style: none;
}
.faqs-item {
  border: 1px solid var(--line);
  border-radius: 18px;
  background: var(--surface);
  overflow: clip;
}
.faqs-item summary {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 14px;
  padding: 16px 18px;
  cursor: pointer;
  list-style: none;
  font-size: clamp(1rem, 1.5vw, 1.18rem);
  font-weight: 900;
  letter-spacing: -0.025em;
  line-height: 1.18;
}
.faqs-item summary::-webkit-details-marker {
  display: none;
}
.faqs-item summary::after {
  content: "+";
  display: grid;
  width: 26px;
  height: 26px;
  place-items: center;
  border-radius: 999px;
  background: var(--soft);
  color: var(--blue);
  font-size: 1rem;
  font-weight: 900;
  flex-shrink: 0;
}
.faqs-item[open] summary::after {
  content: "\2212";
}
.faqs-item-body {
  border-top: 1px solid var(--line);
  padding: 16px 18px 18px;
  color: var(--muted);
  font-size: var(--font-body);
  font-weight: 700;
  line-height: 1.38;
}
.mobile-anchor-bar {
  display: none;
}
@media (max-width: 980px) {
  html {
    scroll-padding-bottom: 96px;
  }
  main {
    padding-bottom: 84px;
  }
  .mobile-anchor-bar {
    position: fixed;
    bottom: 12px;
    left: 12px;
    right: 12px;
    z-index: 40;
    display: flex;
    justify-content: center;
    align-items: center;
    gap: 8px;
    border: 1px solid var(--line);
    border-radius: 999px;
    background: rgba(255, 255, 255, 0.94);
    box-shadow: 0 14px 32px rgba(60, 45, 26, 0.16);
    backdrop-filter: blur(14px);
    padding: 6px 8px;
  }
  .mobile-anchor-bar a {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    min-height: 32px;
    padding: 4px 12px;
    border-radius: 999px;
    font-size: 0.74rem;
    font-weight: 850;
    color: var(--ink);
  }
  @media (hover: none) {
    .mobile-anchor-bar a:hover {
      background: transparent;
      color: var(--ink);
    }
  }
  .mobile-anchor-bar a:focus-visible {
    background: var(--blue);
    color: var(--surface);
    outline: none;
  }
}
@media (max-width: 768px) {
  .nav,
  .hero,
  .footer,
  .faqs-section,
  .answers-section,
  .budget-section,
  .why-section,
  .pricing-section {
    padding-inline: clamp(20px, 6vw, 36px);
  }
}
@media (max-width: 980px) {
  .check-section,
  .pricing-grid,
  .answer-grid,
  .budget-section {
    grid-template-columns: 1fr;
  }
  .check-section > *,
  .form-section,
  .form-section > *,
  .ai-explainer {
    min-width: 0;
    max-width: 100%;
    width: 100%;
  }
}

.dashboard-page {
  display: grid;
  grid-template-columns: minmax(0, 1fr);
  gap: 32px;
}
.dash-hero {
  display: grid;
  grid-template-columns: 1fr;
  gap: 24px;
  align-items: start;
  background: linear-gradient(135deg, #eef3ff 0%, #fff8e8 100%);
  border: 1px solid rgba(230, 222, 208, 0.7);
  border-radius: 28px;
  padding: clamp(24px, 3vw, 40px);
}
.dash-hero-left {
  display: grid;
  gap: 10px;
  max-width: 64ch;
}
.quick-check-widget {
  display: flex;
  align-items: center;
  gap: 10px;
  margin-top: 20px;
  max-width: 640px;
  width: 100%;
}
.quick-check-widget input[type="url"] {
  flex: 1;
  height: 46px;
  min-height: unset;
  padding: 0 16px;
  border: 1.5px solid var(--line);
  border-radius: 12px;
  background: #fff;
  color: var(--ink);
  font-size: 0.9rem;
  font-weight: 500;
  transition: border-color 160ms ease, box-shadow 160ms ease;
  outline: none;
}
.quick-check-widget input[type="url"]:focus,
.quick-check-widget input[type="url"]:focus-visible {
  border-color: var(--blue);
  box-shadow: 0 0 0 3px rgba(47, 98, 233, 0.12);
  outline: none;
}
.quick-check-widget input[type="url"]::placeholder {
  color: #b0a89e;
  font-weight: 400;
}
.quick-check-widget .button.primary {
  flex-shrink: 0;
  height: 46px;
  min-height: unset;
  padding: 0 20px;
  border-radius: 12px;
  font-size: 0.88rem;
  font-weight: 800;
  gap: 6px;
  white-space: nowrap;
  box-shadow: 0 6px 18px rgba(47, 98, 233, 0.18);
}
@media (max-width: 560px) {
  .quick-check-widget {
    flex-direction: column;
    align-items: stretch;
  }
  .quick-check-widget input[type="url"],
  .quick-check-widget .button.primary {
    height: 48px;
    width: 100%;
  }
  .quick-check-widget .button.primary {
    justify-content: center;
  }
}
.dash-kicker {
  margin: 0;
  color: var(--blue);
  font-size: var(--font-xs);
  font-weight: 900;
  text-transform: uppercase;
  letter-spacing: 0.05em;
}
.dash-title {
  margin: 4px 0 6px;
  font-size: var(--font-page);
  font-weight: 900;
  letter-spacing: -0.045em;
  line-height: 1.04;
}
.dash-sub {
  margin: 0;
  max-width: 64ch;
  color: var(--muted);
  font-size: var(--font-label);
  font-weight: 700;
  line-height: 1.35;
}
.dash-stat-grid {
  display: grid;
  grid-template-columns: repeat(4, 1fr);
  gap: 14px;
  min-width: 0;
}
.dash-stat {
  display: grid;
  grid-template-columns: auto 1fr;
  grid-template-rows: auto auto;
  column-gap: 12px;
  row-gap: 2px;
  align-items: center;
  border: 1px solid rgba(230, 222, 208, 0.8);
  border-radius: 18px;
  background: rgba(255, 255, 255, 0.86);
  backdrop-filter: blur(12px);
  padding: 16px 18px;
  transition: transform 200ms ease, box-shadow 200ms ease, border-color 200ms ease;
}
.dash-stat:hover {
  transform: translateY(-2px);
  box-shadow: 0 12px 32px rgba(60, 45, 26, 0.08);
  border-color: rgba(47, 98, 233, 0.25);
}
.dash-stat svg {
  grid-row: 1 / 3;
  align-self: center;
  color: var(--blue);
  margin-bottom: 0;
}
.dash-stat strong {
  grid-column: 2;
  font-size: var(--font-stat);
  font-weight: 900;
  letter-spacing: -0.04em;
  line-height: 1;
}
.dash-stat span {
  grid-column: 2;
  color: var(--muted);
  font-size: var(--font-stat-label);
  font-weight: 700;
  line-height: 1.25;
}
.dash-stat--warn svg {
  color: var(--clay);
}
.dash-stat--warn {
  border-color: rgba(255, 116, 72, 0.2);
}
.dash-section {
  display: grid;
  grid-template-columns: minmax(0, 1fr);
  gap: 16px;
}
.dash-section-head {
  display: flex;
  justify-content: space-between;
  align-items: flex-end;
  flex-wrap: wrap;
  gap: 12px;
}
.dash-section-title {
  margin: 4px 0 0;
  font-size: var(--font-section);
  font-weight: 900;
  letter-spacing: -0.035em;
  line-height: 1.08;
}
.dash-see-all {
  display: inline-flex;
  align-items: center;
  gap: 6px;
  font-size: 0.85rem;
  font-weight: 800;
  color: var(--blue);
  transition: opacity 150ms ease;
