  gap: 24px;
  align-items: center;
  padding: 22px clamp(20px, 18vw, 260px);
  background: rgba(251, 250, 246, 0.9);
  backdrop-filter: blur(18px);
}
.brand {
  display: flex;
  align-items: center;
  gap: 10px;
  width: fit-content;
  font-weight: 900;
  line-height: 0.9;
  letter-spacing: -0.04em;
}
.brand-mark {
  display: grid;
  width: 48px;
  height: 48px;
  place-items: center;
  border-radius: 16px;
  background: var(--ink);
  color: var(--surface);
}
.nav nav {
  display: flex;
  justify-content: center;
  gap: clamp(22px, 5vw, 72px);
  font-size: var(--font-body);
  font-weight: 800;
}
.nav nav a {
  padding: 10px 0;
}
.nav-actions {
  display: flex;
  align-items: center;
  justify-content: flex-end;
  gap: 12px;
}
.theme-toggle {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  width: 40px;
  height: 40px;
  border-radius: 12px;
  border: 1px solid var(--line);
  background: var(--surface);
  color: var(--ink);
  cursor: pointer;
  transition: background 0.2s ease, border-color 0.2s ease;
}
.theme-toggle:hover {
  background: var(--soft);
}
.auth-pill {
  display: inline-flex;
  align-items: center;
  gap: 10px;
  min-height: 44px;
  border-radius: 14px;
  border: 1px solid var(--line);
  background: rgba(255, 255, 255, 0.84);
  padding: 0 14px;
  font-size: var(--font-label);
  font-weight: 850;
  color: var(--muted);
}
.auth-link {
  color: var(--blue);
}

.dashboard-nav-email {
  font-size: var(--font-label);
  font-weight: 800;
  color: var(--muted);
  letter-spacing: -0.02em;
  white-space: nowrap;
}
.dashboard-logout {
  min-height: 40px !important;
  border-radius: 12px !important;
  padding: 0 14px !important;
  font-size: var(--font-label) !important;
}
@media (max-width: 980px) {
  .nav {
    grid-template-columns: 1fr auto;
  }
  .nav nav {
    display: none;
  }
}
@media (max-width: 640px) {
  .nav {
    padding-block: 12px;
    padding-inline: 16px;
    gap: 14px;
  }
  .brand span:last-child {
    display: none;
  }
  .brand-mark {
    width: 40px;
    height: 40px;
    border-radius: 13px;
  }
  .nav-actions {
    gap: 8px;
  }
  .nav .button {
    min-height: 46px;
    border-radius: 16px;
    padding-inline: 14px;
    font-size: var(--font-label);
  }
  .auth-pill {
    min-height: 40px;
    padding: 0 12px;
  }
}

@keyframes skeleton-sweep {
  0%   { background-position: 200% 0; }
  100% { background-position: -200% 0; }
}
.skeleton {
  display: inline-block;
  position: relative;
  overflow: hidden;
  background-color: var(--soft);
  border-radius: 999px;
  vertical-align: middle;
}
.skeleton::after {
  content: "";
  position: absolute;
  inset: 0;
  background-image: linear-gradient(
    90deg,
    rgba(255, 255, 255, 0) 0%,
    rgba(255, 255, 255, 0.55) 50%,
    rgba(255, 255, 255, 0) 100%
  );
  background-size: 200% 100%;
  background-repeat: no-repeat;
  animation: skeleton-sweep 1.4s ease-in-out infinite;
  pointer-events: none;
}
@media (prefers-reduced-motion: reduce) {
  .skeleton::after {
    animation: none;
    background-image: none;
  }
}

.payment-success-page {
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  min-height: 60vh;
  text-align: center;
  padding: 2rem;
}

.profile-page {
  max-width: 560px;
  padding-bottom: 80px;
  display: flex;
  flex-direction: column;
  gap: 14px;
}
.profile-header {
  display: flex;
  flex-direction: column;
  gap: 4px;
  margin-bottom: 12px;
}
.profile-subtitle {
  margin: 0;
  font-size: 0.92rem;
  font-weight: 600;
  color: var(--muted);
}
.profile-identity-card {
  display: flex;
  align-items: center;
  gap: 16px;
  padding: 24px;
  border: 1px solid var(--line);
  border-radius: 20px;
  background: linear-gradient(135deg, #eef3ff 0%, #fff8e8 100%);
  margin-bottom: 8px;
}
.profile-avatar {
  display: grid;
  place-items: center;
  width: 56px;
  height: 56px;
  border-radius: 18px;
  background: var(--blue);
  color: #fff;
  font-size: 1.1rem;
  font-weight: 900;
  letter-spacing: -0.02em;
  flex-shrink: 0;
  box-shadow: 0 4px 14px rgba(47, 98, 233, 0.25);
}
.profile-identity-body {
  display: grid;
  gap: 6px;
  min-width: 0;
}
.profile-identity-email {
  margin: 0;
  font-size: 1rem;
  font-weight: 800;
  color: var(--ink);
  letter-spacing: -0.02em;
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
}
.profile-identity-meta {
  display: flex;
  flex-wrap: wrap;
  gap: 6px;
}
.profile-meta-pill {
  display: inline-flex;
  align-items: center;
  gap: 5px;
  padding: 3px 10px;
  border-radius: 999px;
  background: rgba(47, 98, 233, 0.08);
  color: var(--blue);
  font-size: 0.72rem;
  font-weight: 800;
  letter-spacing: 0.01em;
}
.profile-stats {
  display: grid;
  grid-template-columns: repeat(3, 1fr);
  gap: 10px;
  margin-bottom: 8px;
}
.profile-stat {
  display: flex;
  flex-direction: column;
  gap: 4px;
  padding: 16px;
  border: 1px solid var(--line);
  border-radius: 16px;
  background: var(--surface);
}
.profile-stat-label {
  font-size: 0.7rem;
  font-weight: 800;
  text-transform: uppercase;
  letter-spacing: 0.05em;
  color: var(--muted);
}
.profile-stat-value {
  font-size: 1.35rem;
  font-weight: 900;
  letter-spacing: -0.02em;
  color: var(--ink);
  font-variant-numeric: tabular-nums;
}
@media (max-width: 520px) {
  .profile-stats {
    grid-template-columns: 1fr;
  }
}
.profile-block {
  display: flex;
  align-items: center;
  gap: 14px;
  padding: 16px 20px;
  border: 1px solid var(--line);
  border-radius: 16px;
  background: var(--surface);
}
.profile-block-icon {
  display: grid;
  place-items: center;
  width: 40px;
  height: 40px;
  border-radius: 12px;
  flex-shrink: 0;
  color: var(--surface);
}
.profile-block-icon--blue {
  background: var(--blue);
}
.profile-block-icon--gold {
  background: var(--gold);
  color: var(--ink);
}
.profile-block-body {
  display: grid;
  gap: 2px;
  flex: 1;
  min-width: 0;
}
.profile-block-label {
  margin: 0;
  font-size: 0.72rem;
  font-weight: 800;
  text-transform: uppercase;
  letter-spacing: 0.05em;
  color: var(--muted);
}
.profile-block-value {
  margin: 0;
  font-size: 0.92rem;
  font-weight: 700;
  color: var(--ink);
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
}
.profile-block-action {
  flex-shrink: 0;
  display: inline-flex;
  align-items: center;
  padding: 6px 14px;
  border-radius: 10px;
  border: 1.5px solid var(--blue);
  color: var(--blue);
  font-size: 0.78rem;
  font-weight: 800;
  transition: background 150ms ease, color 150ms ease;
}
.profile-block-action:hover {
  background: var(--blue);
  color: #fff;
}
.profile-divider {
  height: 1px;
  background: var(--line);
  margin: 8px 0;
}
.profile-action-section {
  display: flex;
  flex-direction: column;
  gap: 12px;
  padding: 20px;
  border: 1px solid var(--line);
  border-radius: 16px;
  background: var(--surface);
}
.profile-action-section--danger {
  border-color: rgba(239, 68, 68, 0.2);
  background: #fef2f2;
}
.profile-action-text {
  display: grid;
  gap: 4px;
}
.profile-action-title {
  display: flex;
  align-items: center;
  gap: 7px;
  margin: 0;
  font-size: 0.88rem;
  font-weight: 800;
  color: var(--ink);
  letter-spacing: -0.01em;
}
.profile-action-btn {
  align-self: flex-start;
  display: inline-flex;
  align-items: center;
  gap: 6px;
  padding: 9px 18px;
  border-radius: 10px;
  border: 1.5px solid var(--line);
  background: var(--surface);
  color: var(--ink);
  font-size: 0.82rem;
  font-weight: 800;
  cursor: pointer;
  transition: border-color 150ms ease, background 150ms ease, color 150ms ease;
}
.profile-action-btn:hover {
  border-color: var(--blue);
  color: var(--blue);
}
.profile-action-btn:disabled {
  opacity: 0.5;
  cursor: not-allowed;
}
.profile-action-btn--danger {
  border-color: rgba(239, 68, 68, 0.3);
  color: #dc2626;
}
.profile-action-btn--danger:hover {
  background: #dc2626;
  border-color: #dc2626;
  color: #fff;
}

